blocks.body:
{
    "level": "A1–B1",
    "intro": "W tym dziale znajdziesz <strong>gramatyczne podstawy języka angielskiego</strong>: części mowy, budowę zdania, typy zdań, tryb rozkazujący, spójniki i podstawowy szyk wyrazów.",
    "rules": [
        {
            "label": "Części mowy",
            "color": "emerald",
            "text": "Różne wyrazy pełnią w zdaniu różne role:",
            "example": "noun, verb, adjective, adverb"
        },
        {
            "label": "Budowa zdania",
            "color": "blue",
            "text": "Angielskie zdanie opiera się na wyraźnej strukturze:",
            "example": "Subject + Verb + Object"
        },
        {
            "label": "Szyk słów",
            "color": "amber",
            "text": "Osobny podrozdział pokazuje szyk wyrazów w różnych typach zdań:",
            "example": "statements, questions, adverbials, emphasis"
        }
    ]
}

{
    "title": "1. Co obejmuje ten dział",
    "intro": "To zestaw tematów, od których zwykle zaczyna się naukę angielskiej gramatyki:",
    "items": [
        {
            "label": "Części mowy",
            "title": "Części mowy",
            "subtitle": "Podstawowe role słów: nouns, verbs, adjectives, adverbs i inne."
        },
        {
            "label": "Sentence Structure",
            "title": "Budowa zdania",
            "subtitle": "Najprostszy model zdania i schemat SVO."
        },
        {
            "label": "Sentence Types",
            "title": "Typy zdań",
            "subtitle": "Statements, questions, negatives i imperatives jako najważniejsze modele."
        },
        {
            "label": "Szyk słów",
            "title": "Szyk wyrazów",
            "subtitle": "Osobny blok o statements, questions, adverbials, objects i emphasis."
        }
    ]
}

{
    "title": "2. Jak pracować z tym działem",
    "sections": [
        {
            "label": "Fundament",
            "color": "emerald",
            "description": "Zacznij od <strong>Części mowy</strong> i <strong>Sentence Structure</strong>, żeby zrozumieć role wyrazów i podstawowy szkielet zdania.",
            "examples": [
                {
                    "en": "The student reads a book.",
                    "ua": "Podmiot + czasownik + dopełnienie."
                }
            ]
        },
        {
            "label": "Podstawowe modele",
            "color": "blue",
            "description": "Potem przejdź do <strong>Sentence Types</strong>, <strong>Imperatives</strong> i <strong>Conjunctions</strong>, żeby zobaczyć, jak zdania zmieniają funkcję.",
            "examples": [
                {
                    "en": "Open the window. / I was tired, so I stayed home.",
                    "ua": "Tryb rozkazujący i podstawowe łączenie zdań."
                }
            ]
        },
        {
            "label": "Szyk słów",
            "color": "amber",
            "description": "Podrozdział <strong>Szyk słów</strong> pokazuje, jak ustawienie wyrazów wpływa na znaczenie i naturalność wypowiedzi.",
            "examples": [
                {
                    "en": "She often works at home. / Do you work here?",
                    "ua": "Tutaj najważniejsza jest pozycja wyrazów."
                }
            ]
        }
    ]
}

{
    "title": "3. Krótko o tym dziale",
    "items": [
        "<strong>Części mowy</strong> pomagają zobaczyć funkcję każdego słowa w zdaniu.",
        "<strong>Sentence Structure</strong> i <strong>Sentence Types</strong> dają podstawowe modele zdania.",
        "<strong>Imperatives</strong> i <strong>Conjunctions</strong> pokazują, jak zdania działają w praktyce.",
        "<strong>Szyk słów</strong> pomaga układać wyrazy w naturalnym angielskim szyku.",
        "Razem te tematy dają solidną bazę do dalszej nauki gramatyki."
    ]
}
